<?php&#10;require &#39;config.php&#39;;&#10;&#10;// Fetch all films&#10;$stmt = $pdo->query("SELECT * FROM films ORDER BY created_at DESC");&#10;$films = $stmt->fetchAll();&#10;?>&#10;<!DOCTYPE html>&#10;<html lang="fr">&#10;<head>&#10;    <meta charset="UTF-8">&#10;    <meta name="viewport" content="width=device-width, initial-scale=1.0">&#10;    <title>Films | Unicorn-Multiplex</title>&#10;    <link rel="stylesheet" href="unicorn.css">&#10;    <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;700&amp;display=swap" rel="stylesheet">&#10;</head>&#10;<body>&#10;&#10;<nav class="navbar">&#10;    <div class="logo">🦄 <span>Unicorn</span>-Multiplex</div>&#10;    <ul class="nav-links">&#10;        <li><a href="unicorn.html">Accueil</a></li>&#10;        <li><a href="#" class="active">Films</a></li>&#10;        <li><a href="seances.php">Séances</a></li>&#10;        <li><a href="reservations.php">Réservations</a></li>&#10;        <li><a href="utilisateurs.php">Compte</a></li>&#10;    </ul>&#10;</nav>&#10;&#10;<main>&#10;    <section class="hero">&#10;        <h1>Catalogue Films ✨ (<?php echo count($films); ?>)</h1>&#10;        <p>Sélection galactique disponible dans tous nos cinémas</p>&#10;    </section>&#10;&#10;    <section class="cinema-grid">&#10;        <?php foreach($films as $film): ?>&#10;        <div class="cinema-card">&#10;            <h3><?php echo htmlspecialchars($film[&#39;titre&#39;]); ?></h3>&#10;            <div class="cinema-info">&#10;                <p><strong>Genre:</strong> <?php echo htmlspecialchars($film[&#39;genre&#39;]); ?></p>&#10;                <p><strong>Durée:</strong> <?php echo floor($film[&#39;duree&#39;]/60); ?>h<?php echo $film[&#39;duree&#39;]%60; ?></p>&#10;                <p><strong>Classification:</strong> <?php echo htmlspecialchars($film[&#39;classification&#39;]); ?></p>&#10;                <?php if($film[&#39;affiche_url&#39;]): ?>&#10;                <img src="<?php echo htmlspecialchars($film[&#39;affiche_url&#39;]); ?>" alt="<?php echo htmlspecialchars($film[&#39;titre&#39;]); ?>" style="width:100%; height:200px; object-fit:cover; border-radius:12px; margin-bottom:15px;">&#10;                <?php endif; ?>&#10;                <a href="seances.php?film_id=<?php echo $film[&#39;id&#39;]; ?>" class="btn-select">Voir les Séances</a>&#10;            </div>&#10;        </div>&#10;        <?php endforeach; ?>&#10;        <?php if(empty($films)): ?>&#10;        <div style="text-align:center; padding:40px;">&#10;            <h3>Aucun film disponible</h3>&#10;            <p>Revenez bientôt pour de nouvelles sorties !</p>&#10;        </div>&#10;        <?php endif; ?>&#10;    </section>&#10;</main>&#10;&#10;<footer>&#10;    <p>&amp;copy; 2024 Unicorn-Multiplex - Films centralisés pour tous les établissements</p>&#10;</footer>&#10;&#10;</body>&#10;</html>
